begin;alter table public.lead_reactivation_batches add column if not exists policy_version integer not null default 1,add column if not exists maximum_attempts integer not null default 2 check(maximum_attempts between 1 and 3),add column if not exists cooling_off_hours integer not null default 72 check(cooling_off_hours between 24 and 720),add column if not exists stop_on_reply boolean not null default true,add column if not exists stop_on_opt_out boolean not null default true,add column if not exists official_api_only boolean not null default true,add column if not exists approved_at timestamptz,add column if not exists approved_by uuid references public.profiles(id);alter table public.lead_reactivation_contacts add column if not exists attempt_count integer not null default 0,add column if not exists last_attempt_at timestamptz,add column if not exists next_eligible_at timestamptz,add column if not exists broker_preference text check(broker_preference is null or broker_preference in('keep','change_requested')),add column if not exists stopped_at timestamptz,add column if not exists stop_reason text;create table if not exists public.reactivation_governance_events(id uuid primary key default gen_random_uuid(),organization_id uuid not null references public.organizations(id)on delete cascade,batch_id uuid not null references public.lead_reactivation_batches(id)on delete cascade,actor_id uuid references public.profiles(id),event_type text not null check(event_type in('plan_evaluated','approval_requested','approved','paused_quality','stopped_reply','stopped_opt_out','stopped_invalid_phone')),policy_snapshot jsonb not null default'{}',created_at timestamptz not null default now());alter table public.reactivation_governance_events enable row level security;create policy reactivation_governance_events_scope on public.reactivation_governance_events for select to authenticated using(organization_id=(select public.current_organization_id())and exists(select 1 from public.lead_reactivation_batches b where b.id=batch_id and(select private.can_view_commercial_profile(b.owner_id))));revoke all on public.reactivation_governance_events from anon;revoke insert,update,delete on public.reactivation_governance_events from authenticated;grant select on public.reactivation_governance_events to authenticated;grant all on public.reactivation_governance_events to service_role;
create or replace function private.stop_reactivation_on_suppression()returns trigger language plpgsql security definer set search_path=''as $$begin update public.lead_reactivation_contacts set status='blocked',stopped_at=now(),stop_reason='opt_out',block_reason='opt_out'where organization_id=new.organization_id and phone=new.recipient and status in('imported','pending_approval','queued','sent');return new;end$$;drop trigger if exists stop_reactivation_on_suppression on public.messaging_suppressions;create trigger stop_reactivation_on_suppression after insert on public.messaging_suppressions for each row when(new.channel='whatsapp')execute function private.stop_reactivation_on_suppression();commit;
